// UpdateChannel 更新 channel 的展示名、上游地址、启停状态、优先级与超时；protocol、adapter_key 与凭据不在此更新。
func (q *Queries) UpdateChannel(ctx context.Context, arg UpdateChannelParams) (Channel, error) {
	row := q.db.QueryRow(ctx, updateChannel,
		arg.Name,
		arg.BaseUrl,
		arg.Status,
		arg.Priority,
		arg.TimeoutMs,
		arg.ID,
	)
	var i Channel
	err := row.Scan(
		&i.ID,
		&i.ProviderID,
		&i.Name,
		&i.Protocol,
		&i.AdapterKey,
		&i.BaseUrl,
		&i.Credential,
		&i.Status,
		&i.Priority,
		&i.TimeoutMs,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.RpmLimit,
		&i.TpmLimit,
		&i.RpdLimit,
		&i.LastTestedAt,
		&i.LastTestOk,
		&i.LastTestLatencyMs,
		&i.LastTestError,
		&i.CredentialValid,
		&i.ArchivedAt,
		&i.ConcurrencyLimit,
		&i.UpstreamBillsOnDisconnect,
	)
	return i, err
}

